        fn: "Console Methods Beyond console.log",
        desc: "Structured logging with console.table, group, time, trace, and assert.",
        category: "Debugging Tools",
        subtitle: "Stop using console.log for everything — use the right tool",
        signature: "console.table() | console.group() | console.time() | console.trace()",
        descLong: "console.log is the default but there are better tools for specific jobs: console.table for tabular data, console.group for nested output, console.time/timeEnd for timing, console.trace for stack traces, console.assert for conditional logging, console.count for call counting, console.dir for object inspection.",
        examples: [
                  {
                            "tier": "intro",
                            "code": "// === ENTRY-LEVEL EXAMPLE ===\n// TASK      - Basic usage of Console Methods Beyond console.log — understand the core syntax and behavior.\n// APPROACH  - Simple example with minimal parameters; no edge cases.\n// STRENGTHS - Clear, readable; shows the fundamental pattern.\n// WEAKNESSES- Not production-ready; no error handling or complex scenarios.\n// APPROACH  - The four most useful console methods beyond log\n// STRENGTHS - Shows table, group, time, and trace in one snippet\n// WEAKNESSES- No assert, no count, no dir\n//\n// 1) console.table — tabular display of arrays of objects\nconst users = [\n  { name: 'Alice', age: 30, role: 'admin' },\n  { name: 'Bob',   age: 25, role: 'editor' },\n];\nconsole.table(users);  // renders a table in console\n// 2) console.group — nested, collapsible output\nconsole.group('User Details');\nconsole.log('Name:', 'Alice');\nconsole.group('Address');\nconsole.log('City:', 'NYC');\nconsole.groupEnd();\nconsole.groupEnd();\n// 3) console.time — measure execution duration\nconsole.time('loop');\nfor (let i = 0; i < 1000000; i++) {}\nconsole.timeEnd('loop');  // loop: 3.2ms\n// 4) console.trace — show the call stack\nfunction deep() { console.trace('how did we get here?'); }\nfunction mid()  { deep(); }\nfunction top()  { mid(); }\ntop();"
                  },
                  {
                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Console Methods Beyond console.log — common patterns you'll see in production.\n// APPROACH  - Combine Console Methods Beyond console.log with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - assert, count, dir, conditional logging, string substitution\n// STRENGTHS - Covers the 80% of console debugging\n// WEAKNESSES- No custom formatters, no Node.js util.inspect\n//\n// 1) console.assert — log only if condition is false\nconsole.assert(1 + 1 === 2, 'Math is broken');      // silent (true)\nconsole.assert(1 + 1 === 3, 'Math is broken');      // logs error\n// 2) console.count — count how many times a line executes\nfunction process(item) {\n  console.count('process called');  // increments each call\n}\nprocess('a'); process('b'); process('c');\n// process called: 1, process called: 2, process called: 3\nconsole.countReset('process called');\n// 3) console.dir — show all properties including non-enumerable\nconst obj = Object.create({ inherited: true }, {\n  own: { value: 1, enumerable: true },\n  hidden: { value: 2, enumerable: false },\n});\nconsole.log(obj);   // { own: 1 } — only enumerable\nconsole.dir(obj);   // shows own, hidden, and inherited\n// 4) STRING SUBSTITUTION — printf-style formatting\nconsole.log('User %s has %d items (active: %j)', 'Alice', 42, true);\n// User Alice has 42 items (active: true)\n// 5) CONDITIONAL LOGGING — gate with a flag\nconst DEBUG = true;\nfunction log(...args) { if (DEBUG) console.log('[DEBUG]', ...args); }\nlog('This only shows when DEBUG is true');"
                  },
                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Console Methods Beyond console.log — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - Custom formatters, structured logging, production patterns, decision guide\n// STRENGTHS - Production-grade debugging and logging patterns\n// WEAKNESSES- N/A\n//\n// 1) STRUCTURED LOGGER — replace console.log in production\nclass Logger {\n  #level; #context;\n  constructor(level = 'info', context = {}) {\n    this.#level = level;\n    this.#context = context;\n  }\n  #levels = { debug: 10, info: 20, warn: 30, error: 40 };\n  #log(level, msg, data) {\n    if (this.#levels[level] < this.#levels[this.#level]) return;\n    const entry = {\n      timestamp: new Date().toISOString(),\n      level,\n      msg,\n      ...this.#context,\n      ...(data ? { data } : {}),\n    };\n    const fn = level === 'error' ? console.error : level === 'warn' ? console.warn : console.log;\n    fn(JSON.stringify(entry));\n  }\n  debug(msg, data) { this.#log('debug', msg, data); }\n  info(msg, data)  { this.#log('info', msg, data); }\n  warn(msg, data)  { this.#log('warn', msg, data); }\n  error(msg, data) { this.#log('error', msg, data); }\n  child(context) { return new Logger(this.#level, { ...this.#context, ...context }); }\n}\nconst log = new Logger('debug', { service: 'api' });\nconst reqLog = log.child({ requestId: 'abc123' });\nreqLog.info('Request received', { path: '/users' });\n// {\"timestamp\":\"2024-...\",\"level\":\"info\",\"msg\":\"Request received\",\"service\":\"api\",\"requestId\":\"abc123\",\"data\":{\"path\":\"/users\"}}\n// 2) console.time with labels — benchmark multiple sections\nfunction benchmark(label, fn) {\n  console.time(label);\n  const result = fn();\n  console.timeEnd(label);\n  return result;\n}\nbenchmark('sort 100k', () => Array.from({ length: 100000 }, () => Math.random()).sort());\n// 3) NODE.JS util.inspect — deeper than console.dir\n// const util = require('util');\n// console.log(util.inspect(obj, { depth: null, colors: true, showHidden: true }));\n// 4) CUSTOM UTIL.INSPECT — control how your class appears in console\nclass Matrix {\n  #data;\n  constructor(data) { this.#data = data; }\n  [Symbol.for('nodejs.util.inspect.custom')](depth, opts) {\n    return this.#data.map(row => row.join(' ')).join('\\n');\n  }\n}\nconst m = new Matrix([[1, 2], [3, 4]]);\nconsole.log(m);  // prints \"1 2\\n3 4\" instead of Matrix {}\n// Decision rule:\n//   tabular data (array of objects)                       -> console.table()\n//   nested output with sections                           -> console.group()/groupEnd()\n//   measure duration                                      -> console.time()/timeEnd()\n//   find call stack                                       -> console.trace()\n//   conditional error logging                             -> console.assert()\n//   count function calls                                  -> console.count()\n//   inspect object internals                              -> console.dir()\n//   production logging                                    -> structured Logger class\n//   custom object display in Node                         -> Symbol.for('nodejs.util.inspect.custom')\n//\n// Anti-pattern: console.log(obj) for complex objects;\n//   use console.dir(obj) or console.table(obj) for structured display."
                  }
        ],
